import { prisma } from "@/src/lib/prisma";
import { notFound } from "next/navigation";

export default async function JobDetailPage({
    params,
}: {
    params: Promise<{ id: string }>;
}) {
    const { id } = await params;

    const job = await prisma.job.findUnique({
        where: { id },
    });

    if (!job) {
        notFound();
    }

    return (
        <main style={{ padding: 40, maxWidth: 1100 }}>
            <h1>Campaign Details</h1>

            <div
                style={{
                    marginTop: 20,
                    border: "1px solid #333",
                    padding: 16,
                }}
            >
                <p><strong>ID:</strong> {job.id}</p>
                <p><strong>URL:</strong> {job.url}</p>
                <p><strong>Status:</strong> {job.status}</p>
                <p><strong>Created:</strong> {job.createdAt.toString()}</p>
            </div>

            <div
                style={{
                    marginTop: 24,
                    border: "1px solid #333",
                    padding: 16,
                }}
            >
                <h2>Campaign Settings</h2>
                <p><strong>Platform:</strong> {job.platform || "-"}</p>
                <p><strong>Funnel Stage:</strong> {job.funnelStage || "-"}</p>
                <p><strong>Format Ratio:</strong> {job.formatRatio || "-"}</p>
                <p><strong>Primary Angles:</strong> {job.primaryAngles || "-"}</p>
                <p><strong>Testimonial Usage:</strong> {job.testimonialUsage || "-"}</p>
                <p><strong>CTA Style:</strong> {job.ctaStyle || "-"}</p>
                <p><strong>Visual Style:</strong> {job.visualStyle || "-"}</p>
                <p><strong>Number of Ads:</strong> {job.numberOfAds || "-"}</p>
                <p><strong>Reference Image Types:</strong> {job.referenceImageTypes || "-"}</p>
            </div>

            <div
                style={{
                    marginTop: 24,
                    border: "1px solid #333",
                    padding: 16,
                }}
            >
                <h2>Claude Output</h2>
                <div
                    style={{
                        whiteSpace: "pre-wrap",
                        lineHeight: 1.5,
                        marginTop: 12,
                    }}
                >
                    {job.claudeOutput || "No Claude output yet."}
                </div>
            </div>

            <div
                style={{
                    marginTop: 24,
                    border: "1px solid #333",
                    padding: 16,
                }}
            >
                <h2>Raw Website Text</h2>
                <div
                    style={{
                        whiteSpace: "pre-wrap",
                        lineHeight: 1.5,
                        marginTop: 12,
                        maxHeight: 320,
                        overflow: "auto",
                    }}
                >
                    {job.rawText || "No text fetched yet."}
                </div>
            </div>
        </main>
    );
}
